  1	import { type FC, type FormEvent, useCallback, useState } from 'react';
  2	import { encode } from 'js-base64';
  3	import { FormGroupWithHelpText } from 'src/components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  4	import type { CredentialsEditModeByTypeProps } from 'src/providers/details/tabs/Credentials/components/utils/types';
  5	import { SecretFieldsId } from 'src/providers/utils/constants';
  6	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
  7	
  8	import {
  9	  Alert,
 10	  AlertVariant,
 11	  Button,
 12	  ButtonVariant,
 13	  Divider,
 14	  Form,
 15	  InputGroup,
 16	  TextInput,
 17	} from '@patternfly/react-core';
 18	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 19	import type { ValidationMsg } from '@utils/validation/Validation';
 20	
 21	import { getDecodedValue } from './utils/getDecodedValue';
 22	import { openshiftSecretFieldValidator } from './utils/openshiftSecretFieldValidator';
 23	import CertificateEditSection from './CertificateEditSection';
 24	
 25	const OpenshiftCredentialsEdit: FC<CredentialsEditModeByTypeProps> = ({
 26	  onNewSecretChange,
 27	  secret,
 28	}) => {
 29	  const { t } = useForkliftTranslation();
 30	
 31	  const token = getDecodedValue(secret?.data?.token);
 32	  const insecureSkipVerify = getDecodedValue(secret?.data?.insecureSkipVerify);
 33	  const cacert = getDecodedValue(secret?.data?.cacert);
 34	  const url = getDecodedValue(secret?.data?.url);
 35	
 36	  const [tokenHidden, setTokenHidden] = useState<boolean>(true);
 37	  const [tokenValidation, setTokenValidation] = useState<ValidationMsg>(
 38	    openshiftSecretFieldValidator(SecretFieldsId.Token, token!),
 39	  );
 40	  const [insecureSkipVerifyValidation, setInsecureSkipVerifyValidation] = useState<ValidationMsg>(
 41	    openshiftSecretFieldValidator(SecretFieldsId.InsecureSkipVerify, insecureSkipVerify!),
 42	  );
 43	  const [cacertValidation, setCacertValidation] = useState<ValidationMsg>(
 44	    openshiftSecretFieldValidator(SecretFieldsId.CaCert, cacert!),
 45	  );
 46	
 47	  const handleChange = useCallback(
 48	    (id: SecretFieldsId, value: string) => {
 49	      const validationState = openshiftSecretFieldValidator(id, value);
 50	
 51	      if (id === SecretFieldsId.Token) setTokenValidation(validationState);
 52	      if (id === SecretFieldsId.InsecureSkipVerify)
 53	        setInsecureSkipVerifyValidation(validationState);
 54	      if (id === SecretFieldsId.CaCert) setCacertValidation(validationState);
 55	
 56	      // don't trim fields that allow spaces
 57	      const encodedValue =
 58	        id === SecretFieldsId.CaCert ? encode(value ?? '') : encode(value?.trim() ?? '');
 59	
 60	      onNewSecretChange({ ...secret, data: { ...secret.data, [id]: encodedValue } });
 61	    },
 62	    [onNewSecretChange, secret],
 63	  );
 64	
 65	  const onClickToggleToken = () => {
 66	    setTokenHidden(!tokenHidden);
 67	  };
 68	
 69	  const onChangeToken: (_event: FormEvent<HTMLInputElement>, value: string) => void = (
 70	    _event,
 71	    value,
 72	  ) => {
 73	    handleChange(SecretFieldsId.Token, value);
 74	  };
 75	
 76	  const onChangeInsecure: (_event: FormEvent<HTMLInputElement>, checked: boolean) => void = (
 77	    _event,
 78	    checked,
 79	  ) => {
 80	    handleChange(SecretFieldsId.InsecureSkipVerify, checked ? 'true' : 'false');
 81	  };
 82	
 83	  const onDataChange: (data: string) => void = (data) => {
 84	    handleChange(SecretFieldsId.CaCert, data);
 85	  };
 86	
 87	  return (
 88	    <Form isWidthLimited className="forklift-section-secret-edit">
 89	      <FormGroupWithHelpText
 90	        label={t('Service account bearer token')}
 91	        isRequired
 92	        fieldId="token"
 93	        helperText={tokenValidation.msg}
 94	        helperTextInvalid={tokenValidation.msg}
 95	        validated={tokenValidation.type}
 96	      >
 97	        <InputGroup>
 98	          <TextInput
 99	            spellCheck="false"
100	            isRequired
101	            type={tokenHidden ? 'password' : 'text'}
102	            aria-label="Token input"
103	            onChange={onChangeToken}
104	            value={token}
105	            validated={tokenValidation.type}
106	          />
107	          <Button
108	            variant={ButtonVariant.control}
109	            onClick={onClickToggleToken}
110	            aria-label={tokenHidden ? 'Show token' : 'Hide token'}
111	          >
112	            {tokenHidden ? <EyeIcon /> : <EyeSlashIcon />}
113	          </Button>
114	        </InputGroup>
115	      </FormGroupWithHelpText>
116	
117	      <Alert
118	        variant={AlertVariant.info}
119	        isInline
120	        title={
121	          <ForkliftTrans>
122	            If both 'URL' and 'Service account bearer token' fields are left empty, the local
123	            OpenShift cluster is used.
124	          </ForkliftTrans>
125	        }
126	      ></Alert>
127	
128	      <Divider />
129	
130	      <CertificateEditSection
131	        insecureSkipVerifyValidation={insecureSkipVerifyValidation}
132	        insecureSkipVerify={insecureSkipVerify}
133	        cacertValidation={cacertValidation}
134	        cacert={cacert}
135	        url={url}
136	        onChangeInsecure={onChangeInsecure}
137	        onDataChange={onDataChange}
138	      />
139	    </Form>
140	  );
141	};
142	
143	export default OpenshiftCredentialsEdit;

